formulas.generateAns:
(numDigits, sumDigits) => {
        let digits = new Array(numDigits).fill(0);
        digits[0] = 1; // Smallest possible first digit
        let currentSum = 1;

        for (let i = numDigits - 1; i >= 1; i--) {
            let canAdd = Math.min(sumDigits - currentSum, 9 - digits[i]);
            digits[i] += canAdd;
            currentSum += canAdd;
        }

        if (currentSum < sumDigits) {
            digits[0] += (sumDigits - currentSum);
        }
        return parseInt(digits.join(''));
      }
